def initialize_board():
    board = [[" " for _ in range(8)] for _ in range(8)]
    for i in range(3):
        for j in (1, 3, 5, 7):
            if (i + j) % 2 == 1:
                board[i][j] = 'B'
    for i in range(5, 8):
        for j in (0, 2, 4, 6):
            if (i + j) % 2 == 1:
                board[i][j] = 'R'
    return board

def print_board(board):
    for row in board:
        print(" ".join(row))
    print()

def is_valid_move(board, start, end):
    piece = board[start[0]][start[1]]
    if piece == " " or (piece.islower() and end[0] > start[0]) or (piece.isupper() and end[0] < start[0]):
        return False
    row_diff = abs(start[0] - end[0])
    col_diff = abs(start[1] - end[1])
    if row_diff == 2 and col_diff == 2:
        intermediate_row = (start[0] + end[0]) // 2
        intermediate_col = (start[1] + end[1]) // 2
        if board[intermediate_row][intermediate_col] in "BR":
            return True
    elif row_diff == 1 and col_diff == 1:
        return True
    return False

def make_move(board, start, end):
    piece = board[start[0]][start[1]]
    board[start[0]][start[1]] = " "
    if abs(end[0] - start[0]) == 2:
        intermediate_row = (start[0] + end[0]) // 2
        intermediate_col = (start[1] + end[1]) // 2
        board[intermediate_row][intermediate_col] = " "
    board[end[0]][end[1]] = piece

def is_game_over(board):
    red_pieces = sum(row.count('R') for row in board)
    black_pieces = sum(row.count('B') for row in board)
    return red_pieces == 0 or black_pieces == 0

def main():
    board = initialize_board()
    current_player = 'R'
    while True:
        print_board(board)
        start = input(f"Player {current_player}, enter your move (start end): ").split()
        start, end = tuple(map(int, start)), tuple(map(int, end))
        if not is_valid_move(board, start, end):
            print("Invalid move. Try again.")
            continue
        make_move(board, start, end)
        current_player = 'B' if current_player == 'R' else 'R'
        if is_game_over(board):
            print_board(board)
            print(f"Player {'B' if current_player == 'R' else 'R'} wins!")
            break

if __name__ == "__main__":
    main()
```

