import numpy as np

class Checkers:
    def __init__(self):
        self.board = self.create_board()
        self.current_player = 'b'
        self.game_over = False
        self.winner = None

    def create_board(self):
        board = np.zeros((8, 8), dtype=str)
        for i in range(3):
            for j in range(0, 8, 2):
                if (i + j) % 2 == 1:
                    board[i][j] = 'b'
        for i in range(5, 8):
            for j in range(0, 8, 2):
                if (i + j) % 2 == 1:
                    board[i][j] = 'r'
        return board

    def print_board(self):
        for row in self.board:
            print(" ".join(row))
        print()

    def is_valid_move(self, from_pos, to_pos):
        if not (0 <= from_pos[0] < 8 and 0 <= from_pos[1] < 8 and
                0 <= to_pos[0] < 8 and 0 <= to_pos[1] < 8):
            return False
        piece = self.board[from_pos[0], from_pos[1]]
        if piece != self.current_player and piece != self.current_player.upper():
            return False
        if self.board[to_pos[0], to_pos[1]] != '':
            return False
        if abs(from_pos[0] - to_pos[0]) == 1:
            return True
        elif abs(from_pos[0] - to_pos[0]) == 2 and abs(from_pos[1] - to_pos[1]) == 2:
            intermediate = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
            if self.board[intermediate[0], intermediate[1]] != self.current_player.upper() and \
               abs(from_pos[0] - intermediate[0]) == 1 and abs(from_pos[1] - intermediate[1]) == 1:
                return True
        return False

    def make_move(self, from_pos, to_pos):
        if not self.is_valid_move(from_pos, to_pos):
            print("Invalid move. Try again.")
            return
        piece = self.board[from_pos[0], from_pos[1]]
        self.board[to_pos[0], to_pos[1]] = piece
        self.board[from_pos[0], from_pos[1]] = ''
        if abs(from_pos[0] - to_pos[0]) == 2:
            intermediate = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
            self.board[intermediate[0], intermediate[1]] = ''
        if self.current_player == 'b' and to_pos[0] == 7:
            self.board[to_pos[0], to_pos[1]] = piece.upper()
        elif self.current_player == 'r' and to_pos[0] == 0:
            self.board[to_pos[0], to_pos[1]] = piece.upper()
        if not any(self.board[self.current_player == 'b'].tolist()):
            self.winner = 'r'
            self.game_over = True
        elif not any(self.board[self.current_player == 'r'].tolist()):
            self.winner = 'b'
            self.game_over = True
        else:
            self.current_player = 'b' if self.current_player == 'r' else 'r'

    def play_game(self):
        while not self.game_over:
            self.print_board()
            from_pos = input(f"Player {self.current_player}, enter move (e.g., 2,1 to 3,2): ").split(',')
            from_pos = (int(from_pos[0]), int(from_pos[1]))
            to_pos = input(f"Player {self.current_player}, enter move (e.g., 2,1 to 3,2): ").split(',')
            to_pos = (int(to_pos[0]), int(to_pos[1]))
            self.make_move(from_pos, to_pos)
        self.print_board()
        print(f"Game over. Player {self.winner} wins!")

if __name__ == "__main__":
    game = Checkers()
    game.play_game()
